function cargarPerfilAjax(url,push=true){const contenido=document.getElementById('contenido');axios.get(url).then(res=>{contenido.innerHTML=res.data;if(push)history.pushState({url},'',url);inicializarVerPerfil();}).catch(err=>{console.error('Error al cargar el perfil:',err);contenido.innerHTML='<p>Error al cargar el perfil.</p>';});}function inicializarVerPerfil(){const enlaces=document.querySelectorAll('a.ver-perfil');enlaces.forEach(enlace=>{enlace.removeEventListener('click',manejarClickVerPerfil);enlace.addEventListener('click',manejarClickVerPerfil);});}function manejarClickVerPerfil(e){e.preventDefault();const url=this.getAttribute('href');cargarPerfilAjax(url);}document.addEventListener('DOMContentLoaded',()=>{inicializarVerPerfil();window.addEventListener('popstate',e=>{if(e.state&&e.state.url){cargarPerfilAjax(e.state.url,false);}});});